+/// Parsed Accept-Language header.
+///
+/// # Example
+///
+/// ```ignore
+/// use fastapi_core::AcceptLanguageHeader;
+///
+/// async fn handler(lang: AcceptLanguageHeader) -> impl IntoResponse {
+///     let locale = lang.negotiate(&["en", "fr", "de"]).unwrap_or("en");
+///     // Use locale for response
+/// }
+/// ```
